#[rustfmt::skip]
impl Input {
    pub fn route(&self) -> InputRoute {
        match self {
            Self::Summary(_) => InputRoute::Summary,
            Self::MessageTrace(_) => InputRoute::MessageTrace,
            Self::ChannelState(_) => InputRoute::ChannelState,
            Self::ForwardMessage(_) => InputRoute::ForwardMessage,
            Self::SubmitRoutedObjects(_) => InputRoute::SubmitRoutedObjects,
            Self::SessionClientHello(_) => InputRoute::SessionClientHello,
            Self::SessionClientProof(_) => InputRoute::SessionClientProof,
            Self::SessionData(_) => InputRoute::SessionData,
        }
    }
    pub fn short_header(&self) -> u64 {
        match self {
            Self::Summary(_) => short_header::INPUT_SUMMARY,
            Self::MessageTrace(_) => short_header::INPUT_MESSAGE_TRACE,
            Self::ChannelState(_) => short_header::INPUT_CHANNEL_STATE,
            Self::ForwardMessage(_) => short_header::INPUT_FORWARD_MESSAGE,
            Self::SubmitRoutedObjects(_) => short_header::INPUT_SUBMIT_ROUTED_OBJECTS,
            Self::SessionClientHello(_) => short_header::INPUT_SESSION_CLIENT_HELLO,
            Self::SessionClientProof(_) => short_header::INPUT_SESSION_CLIENT_PROOF,
            Self::SessionData(_) => short_header::INPUT_SESSION_DATA,
        }
    }
    pub fn route_from_short_header(header: u64) -> Result<InputRoute, SignalFrameError> {
        match header {
            short_header::INPUT_SUMMARY => Ok(InputRoute::Summary),
            short_header::INPUT_MESSAGE_TRACE => Ok(InputRoute::MessageTrace),
            short_header::INPUT_CHANNEL_STATE => Ok(InputRoute::ChannelState),
            short_header::INPUT_FORWARD_MESSAGE => Ok(InputRoute::ForwardMessage),
            short_header::INPUT_SUBMIT_ROUTED_OBJECTS => {
                Ok(InputRoute::SubmitRoutedObjects)
            }
            short_header::INPUT_SESSION_CLIENT_HELLO => {
                Ok(InputRoute::SessionClientHello)
            }
            short_header::INPUT_SESSION_CLIENT_PROOF => {
                Ok(InputRoute::SessionClientProof)
            }
            short_header::INPUT_SESSION_DATA => Ok(InputRoute::SessionData),
            _ => {
                Err(SignalFrameError::UnknownHeader {
                    root_enum: "Input",
                    header,
                })
            }
        }
    }
    pub fn encode_signal_frame(&self) -> Result<Vec<u8>, SignalFrameError> {
        let archive = rkyv::to_bytes::<rkyv::rancor::Error>(self)
            .map_err(|_| SignalFrameError::ArchiveEncode)?;
        let mut frame = Vec::with_capacity(
            SIGNAL_SHORT_HEADER_BYTE_COUNT + archive.len(),
        );
        frame.extend_from_slice(&self.short_header().to_le_bytes());
        frame.extend_from_slice(&archive);
        Ok(frame)
    }
    pub fn decode_signal_frame(
        frame: &[u8],
    ) -> Result<(InputRoute, Self), SignalFrameError> {
        if frame.len() < SIGNAL_SHORT_HEADER_BYTE_COUNT {
            return Err(SignalFrameError::FrameTooShort {
                found: frame.len(),
            });
        }
        let mut header_bytes = [0_u8; SIGNAL_SHORT_HEADER_BYTE_COUNT];
        header_bytes.copy_from_slice(&frame[..SIGNAL_SHORT_HEADER_BYTE_COUNT]);
        let header = u64::from_le_bytes(header_bytes);
        let route = Self::route_from_short_header(header)?;
        let value = rkyv::from_bytes::<
            Self,
            rkyv::rancor::Error,
        >(&frame[SIGNAL_SHORT_HEADER_BYTE_COUNT..])
            .map_err(|_| SignalFrameError::ArchiveDecode)?;
        let expected = value.short_header();
        if expected != header {
            return Err(SignalFrameError::HeaderMismatch {
                expected,
                found: header,
            });
        }
        Ok((route, value))
    }
}

